const Logo: React.FC<LogoProps> = ({
    size = 'small',
    variant = 'default',
    className = '',
}) => {
    const logoSvg = size === 'small' ? <NdSvg /> : <NederlandsDagbladSvg />;

    if (variant === 'with-square') {
        return (
            <div className={`inline-flex ${className}`}>
                {size === 'full' ? <NederlandsDagbladWithSquareSvg /> : <NdWithSquareSvg />}
            </div>
        );
    }

    return (
        <div className={`inline-flex ${className}`}>
            {logoSvg}
        </div>
    );
};

export default Logo;
